class PID:
    def __init__(self, Kp, Ki, Kd, u_max=float('inf')):
        self.Kp, self.Ki, self.Kd = Kp, Ki, Kd
        self.u_max = u_max
        self.e_int = 0.0
        self.e_prev = 0.0

    def step(self, setpoint, measurement, dt):
        e = setpoint - measurement
        self.e_int += e * dt
        if self.Ki:
            lim = self.u_max / abs(self.Ki)
            self.e_int = max(-lim, min(lim, self.e_int))
        e_dot = (e - self.e_prev) / dt if dt > 0 else 0.0
        self.e_prev = e
        u = self.Kp*e + self.Ki*self.e_int + self.Kd*e_dot
        return max(-self.u_max, min(self.u_max, u))

// Drop-in for a 1 kHz controller. No heap, no exceptions, no GIL.
class Pid {
public:
  Pid(double kp, double ki, double kd, double u_max = 1e30)
      : kp_(kp), ki_(ki), kd_(kd), u_max_(u_max) {}

  double step(double setpoint, double measurement, double dt) {
    const double e = setpoint - measurement;
    e_int_ += e * dt;
    if (ki_ != 0.0) {
      const double lim = u_max_ / std::abs(ki_);
      if (e_int_ >  lim) e_int_ =  lim;
      if (e_int_ < -lim) e_int_ = -lim;
    }
    const double e_dot = (dt > 0.0) ? (e - e_prev_) / dt : 0.0;
    e_prev_ = e;
    double u = kp_*e + ki_*e_int_ + kd_*e_dot;
    if (u >  u_max_) u =  u_max_;
    if (u < -u_max_) u = -u_max_;
    return u;
  }

private:
  double kp_, ki_, kd_, u_max_;
  double e_int_  = 0.0;
  double e_prev_ = 0.0;
};

